import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('brain'); 

  useEffect(() => {
    const timer1 = setTimeout(() => setStage('letters'), 1500);
    const timer2 = setTimeout(() => setStage('main'), 4000);
    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' }, // Duplicated for infinite loop
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders for retention.' }, // Duplicated for infinite loop
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
  ];

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden">

      {/* 1. INTRO ANIMATIONS */}
      <AnimatePresence mode="wait">
        {stage === 'brain' && (
          <motion.div
            key="brain-stage"
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1.2, opacity: 1 }}
            exit={{ scale: 2, opacity: 0 }}
            className="fixed inset-0 flex items-center justify-center z-50 bg-white"
          >
            <motion.svg 
              width="120" height="120" viewBox="0 0 24 24" 
              fill="none" stroke="black" strokeWidth="1.5"
              animate={{ strokeWidth: [1.5, 2.5, 1.5] }}
              transition={{ repeat: Infinity, duration: 1 }}
            >
              <path d="M9.5 2A2.5 2.5 0 0 1 12 4.5v15a2.5 2.5 0 0 1-4.96.44 2.5 2.5 0 0 1-2.96-3.08 3 3 0 0 1-.34-5.58 2.5 2.5 0 0 1 1.32-4.24 2.5 2.5 0 0 1 4.44-2.48Z" />
              <path d="M14.5 2A2.5 2.5 0 0 0 12 4.5v15a2.5 2.5 0 0 0 4.96.44 2.5 2.5 0 0 0 2.96-3.08 3 3 0 0 0 .34-5.58 2.5 2.5 0 0 0-1.32-4.24 2.5 2.5 0 0 0-4.44-2.48Z" />
            </motion.svg>
          </motion.div>
        )}

        {stage === 'letters' && (
          <motion.div
            key="c-stage"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0 }}
          >
            <svg width="300" height="300" viewBox="0 0 100 100" className="stroke-black fill-none">
              <motion.path
                d="M75 25 C 20 20, 20 80, 75 75"
                strokeWidth="5"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1.8, ease: "anticipate" }}
              />
              <motion.path
                d="M25 25 C 80 20, 80 80, 25 75"
                strokeWidth="5"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1.8, ease: "anticipate", delay: 0.2 }}
              />
            </svg>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 2. MAIN CONTENT */}
      {stage === 'main' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 1.2 }}>

          {/* HEADER - ENLARGED LOGO */}
          <header className="fixed top-0 left-0 right-0 h-32 flex items-center justify-between px-10 z-40 bg-white/50 backdrop-blur-md">
            <div className="flex items-center">
              <img src="/logo.jpeg" alt="logo" className="w-28 h-28 object-contain rounded-xl shadow-md" />
            </div>
            <div className="flex items-center space-x-8">
              <button className="text-sm font-semibold hover:tracking-widest transition-all">LOG IN</button>
              <button className="px-8 py-3 bg-black text-white rounded-full text-xs font-bold tracking-widest hover:bg-gray-800 transition-all">
                SIGN UP
              </button>
            </div>
          </header>

          {/* HERO */}
          <section className="h-screen flex flex-col items-center justify-center text-center px-6">
            <h1 className="text-7xl md:text-9xl font-serif text-black mb-4">
              Welcome to <br />
              <span className="font-light italic text-gray-800">CourseCraft</span>
            </h1>
            <p className="text-lg md:text-xl tracking-[0.3em] uppercase text-gray-400 font-light">
              Skip the scroll. <span className="text-black font-medium">Learn the goal</span>
            </p>
          </section>

          {/* FEATURES SECTION - BRAND COLOR & ROTATING ANIMATION */}
          <section className="py-24 bg-[#0B3954] text-white overflow-hidden">
            <div className="mb-16 px-10">
              <h2 className="text-4xl font-serif text-white/90">Tailored Experience</h2>
            </div>

            {/* ROW 1: Auto-moving Right to Left */}
            <div className="flex mb-10 overflow-hidden">
              <motion.div 
                className="flex space-x-6 px-6"
                animate={{ x: [0, -1000] }}
                transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
              >
                {featuresRow1.map((f, idx) => (
                  <div key={idx} className="min-w-[400px] h-64 p-10 bg-white/5 border border-white/10 rounded-3xl flex flex-col justify-end">
                    <h3 className="text-2xl font-medium mb-2">{f.title}</h3>
                    <p className="text-white/60">{f.desc}</p>
                  </div>
                ))}
              </motion.div>
            </div>

            {/* ROW 2: Auto-moving Left to Right */}
            <div className="flex overflow-hidden">
              <motion.div 
                className="flex space-x-6 px-6"
                animate={{ x: [-1000, 0] }}
                transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
              >
                {featuresRow2.map((f, idx) => (
                  <div key={idx} className="min-w-[400px] h-64 p-10 bg-white/5 border border-white/10 rounded-3xl flex flex-col justify-end">
                    <h3 className="text-2xl font-medium mb-2">{f.title}</h3>
                    <p className="text-white/60">{f.desc}</p>
                  </div>
                ))}
              </motion.div>
            </div>
          </section>

          <footer className="h-40 flex items-center justify-center border-t border-gray-100 bg-white">
            <p className="text-gray-400 text-sm italic">Skip the Scroll. Learn the Goal. </p>
          </footer>
        </motion.div>
      )}
    </div>
  );
};

export default WelcomePage;
